    let status = response.status();
    let headers = response.headers().clone();

    // Limit response body size
    let content_length = headers
        .get(reqwest::header::CONTENT_LENGTH)
        .and_then(|v| v.to_str().ok())
        .and_then(|v| v.parse::<usize>().ok());

    if let Some(len) = content_length {
        if len > MAX_RESPONSE_SIZE {
            return (
                StatusCode::BAD_GATEWAY,
                "Upstream response too large",
            )
                .into_response();
        }
    }

    // Read body with size limit
    let body_bytes = match response.bytes().await {
        Ok(bytes) => {
            if bytes.len() > MAX_RESPONSE_SIZE {
                return (
                    StatusCode::BAD_GATEWAY,
                    "Upstream response too large",
                )
                    .into_response();
            }
            bytes
        }
        Err(e) => {
            eprintln!("Failed to read upstream body: {}", e);
            return (StatusCode::BAD_GATEWAY, "Failed to read upstream response").into_response();
        }
    };

    // Build the proxied response, forwarding only safe headers
    let mut builder = axum::http::Response::builder().status(StatusCode::from_u16(status.as_u16()).unwrap_or(StatusCode::OK));

    // Forward only Content-Type header from upstream
    if let Some(ct) = headers.get(reqwest::header::CONTENT_TYPE) {
        if let Ok(ct_str) = ct.to_str() {
            builder = builder.header("Content-Type", ct_str);
        }
    }

    // Add security headers
    builder = builder
        .header("X-Content-Type-Options", "nosniff")
        .header("X-Proxy-Source", "WebhookProxy");

    match builder.body(axum::body::Body::from(body_bytes)) {
        Ok(resp) => resp.into_response(),
        Err(e) => {
            eprintln!("Failed to build response: {}", e);
            (StatusCode::INTERNAL_SERVER_ERROR, "Failed to construct response").into_response()
        }
    }
